import{_ as t,o as a,c as o,a3 as i}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"模板语法与宏联动","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/quick-actions/template-syntax.md","filePath":"user-guide/tools/llm-chat/quick-actions/template-syntax.md","lastUpdated":1778244893000}'),l={name:"user-guide/tools/llm-chat/quick-actions/template-syntax.md"};function n(r,e,s,c,d,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<div><h1 id="模板语法与宏联动" tabindex="-1">模板语法与宏联动 <a class="header-anchor" href="#模板语法与宏联动" aria-label="Permalink to &quot;模板语法与宏联动&quot;">​</a></h1><p>快捷操作的核心在于其灵活的模板语法，允许你定义复杂的文本结构。</p><h2 id="input-占位符" tabindex="-1">{{input}} 占位符 <a class="header-anchor" href="#input-占位符" aria-label="Permalink to &quot;{{input}} 占位符&quot;">​</a></h2><p><code>{{input}}</code> 是快捷操作中最核心的占位符：</p><ul><li><strong>行为</strong>： <ul><li>如果输入框中有选中的文本，<code>{{input}}</code> 将被替换为选中的文本。</li><li>如果输入框中没有选中的文本，<code>{{input}}</code> 将被替换为输入框中的全部文本。</li></ul></li><li><strong>用途</strong>：实现“包装”模式。例如模板内容为 <code>请翻译以下内容：\\n\\n{{input}}</code>。</li></ul><h2 id="文本后处理-line-processing" tabindex="-1">文本后处理 (Line Processing) <a class="header-anchor" href="#文本后处理-line-processing" aria-label="Permalink to &quot;文本后处理 (Line Processing)&quot;">​</a></h2><p>系统支持对生成的每一行内容进行自动化处理：</p><ul><li><strong>行前缀/后缀</strong>：例如为每一行添加 <code>&gt; </code> 实现批量引用。</li><li><strong>正则替换</strong>：支持在包装完成后，对结果进行二次正则清洗。</li></ul><h2 id="与宏系统联动" tabindex="-1">与宏系统联动 <a class="header-anchor" href="#与宏系统联动" aria-label="Permalink to &quot;与宏系统联动&quot;">​</a></h2><p>快捷操作完整集成了系统的<strong>宏引擎 (Macro Engine)</strong>：</p><ul><li><strong>动态注入</strong>：你可以在模板中使用任何系统宏，如 <code>{{time}}</code>、<code>{{date}}</code>、<code>{{user}}</code> 等。</li><li><strong>变量操作</strong>：通过 <code>{{getvar::key}}</code> 获取会话变量，或通过 <code>{{setvar::key::value}}</code> 在执行快捷操作的同时修改会话状态。</li><li><strong>自动补全</strong>：在快捷操作编辑器中，输入 <code>{{</code> 即可触发宏的自动补全提示。</li></ul><h2 id="包装模式-vs-指令模式" tabindex="-1">包装模式 vs 指令模式 <a class="header-anchor" href="#包装模式-vs-指令模式" aria-label="Permalink to &quot;包装模式 vs 指令模式&quot;">​</a></h2><ul><li><strong>包装模式</strong>：通常包含 <code>{{input}}</code>，用于处理用户现有的输入。</li><li><strong>指令模式</strong>：不包含 <code>{{input}}</code>，直接发送预定义的指令（如“继续生成”、“总结全文”）。配合“自动发送”开关，可实现一键触达。</li></ul><hr><p><strong>相关阅读</strong>：</p><ul><li><a href="./">快捷操作概览</a></li><li><a href="./management">管理与导入导出</a></li><li><a href="./../macro-system/macro-reference">宏系统参考</a></li></ul></div>',1)])])}const h=t(l,[["render",n]]);export{g as __pageData,h as default};
